uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw*12;
    vec2 uv_y = vUv;//0.5 + (vUvOriginal-0.5)*1.00 + vec2(0,-0.8)*uTexSize.zw*0;
    vec3 dx = ( GetBlur1(uv_y + vec2(1,0)*d) - GetBlur1(uv_y-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(uv_y + vec2(0,1)*d) - GetBlur1(uv_y-vec2(0,1)*d) );
    uv_y = uv_y + vec2(dx.y,dy.y)*uTexSize.zw*2;

    vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw*0.8 + rand_frame.xy;
    vec2 uv_bg = vUvOriginal -(vUvOriginal-vUv)*0.4 + vec2(dx.x,dy.x)*uTexSize.zw*2 + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*4;


   ret.y = texture( sampler_main, vUv ).y;
   ret.y += (ret.y - GetBlur1(vUv).y)*0.1 - 0.015;
   dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;

uv_bg = vUvOriginal +(vUvOriginal-vUv)*0.8 + (texture(sampler_noise_lq, dither_uv).xyz-0.5)*uTexSize.zw*0;
ret.z = GetPixel(uv_bg).z*0.94 - 0.004;

vec2 zoom = 1.75;
vec2 c = vec2(0.4,0.74);

 vec2 my_uv2 = (vUvOriginal-0.5)*zoom;
 my_uv2 = vec2(my_uv2.x*my_uv2.x - my_uv2.y*my_uv2.y, 2*my_uv2.x*my_uv2.y) + c; // u -> u^2 + c


    d = uTexSize.zw*8;
    vec2 uv_d = my_uv2;
    dx = ( GetBlur1(uv_d+vec2(1,0)*d)-GetBlur1(uv_d-vec2(1,0)*d) );
    dy = ( GetBlur1(uv_d+vec2(0,1)*d)-GetBlur1(uv_d-vec2(0,1)*d) );
    uv_y = uv_d+vec2(dx.x,dy.x)*uTexSize.zw*4;

ret.x = texture( sampler_fc_main, uv_y).x;


